config.code:
const impressions = Number($node['x_ads_metrics'].json.impressions) || 0;
const urlClicks = Number($node['x_ads_metrics'].json.url_clicks) || 0;
const ctr = impressions > 0 ? urlClicks / impressions : 0;
return [{ json: { ctr, impressions, url_clicks: urlClicks } }];

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const week = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}週`;

const ctr = $node['calc_ctr'].json.ctr;
const signups = Number($node['ga4_signups'].json.signups) || 0;
const prevRow = $node['load_prev_metrics'].json || {};

const prevCtrRaw = prevRow.prev_ctr;
const prevSignupsRaw = prevRow.prev_signups;

const prev_ctr = (prevCtrRaw === undefined || prevCtrRaw === '' || prevCtrRaw === null) ? null : Number(prevCtrRaw);
const prev_signups = (prevSignupsRaw === undefined || prevSignupsRaw === '' || prevSignupsRaw === null) ? null : Number(prevSignupsRaw);

const payload = { week, ctr, signups, prev_ctr, prev_signups };

return [{ json: { ...payload, payloadJsonString: JSON.stringify(payload) } }];

const stdout = $json.stdout || $json.data || '';
if (!stdout) {
  throw new Error('PDCA script returned empty stdout');
}
let parsed;
try {
  parsed = JSON.parse(stdout.trim());
} catch (e) {
  throw new Error('Failed to parse PDCA stdout as JSON: ' + e.message);
}
return [{ json: parsed }];

